mapper.select:
select v.*,
       case when exists (
           select 1
           from tbl_post_like pl
           where pl.post_id = v.id
             and pl.member_id = #{memberId}
       ) then true else false end as is_liked,
       case when exists (
           select 1
           from tbl_bookmark b
           where b.post_id = v.id
             and b.member_id = #{memberId}
       ) then true else false end as is_bookmarked
from view_post_feed v
         join tbl_follow f on f.following_id = v.member_id
where f.follower_id = #{memberId}

      and cast(v.created_datetime as date) >= cast(#{startDate} as date)


      and cast(v.created_datetime as date) <= cast(#{endDate} as date)

  and v.member_id not in (
      select bl.blocked_id
      from tbl_block bl
      where bl.blocker_id = #{memberId}
  )
  and v.member_id not in (
      select r.target_id
      from tbl_report r
      where r.reporter_id = #{memberId}
        and r.target_type = 'member'
  )
  and v.id not in (
      select r.target_id
      from tbl_report r
      where r.reporter_id = #{memberId}
        and r.target_type = 'post'
  )
order by v.created_datetime desc
limit #{criteria.count}
offset #{criteria.offset}

select count(*)
from view_post_feed v
         join tbl_follow f on f.following_id = v.member_id
where f.follower_id = #{memberId}

      and cast(v.created_datetime as date) >= cast(#{startDate} as date)


      and cast(v.created_datetime as date) <= cast(#{endDate} as date)

  and v.member_id not in (
      select bl.blocked_id
      from tbl_block bl
      where bl.blocker_id = #{memberId}
  )
  and v.member_id not in (
      select r.target_id
      from tbl_report r
      where r.reporter_id = #{memberId}
        and r.target_type = 'member'
  )
  and v.id not in (
      select r.target_id
      from tbl_report r
      where r.reporter_id = #{memberId}
        and r.target_type = 'post'
  )
